tests.fallback_command:
sh -lc 'set -eu; command -v cc >/dev/null || { echo "tamandua_execveat_memfd_live missing=cc"; exit 125; }; work=$(mktemp -d /tmp/tamandua-execveat.XXXXXX); trap "rm -rf $work" EXIT; cat > "$work/execveat_memfd.c" <<"EOF"
#define _GNU_SOURCE
#include <errno.h>
#include <fcntl.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/sendfile.h>
#include <sys/syscall.h>
#include <sys/wait.h>
#include <unistd.h>
#ifndef AT_EMPTY_PATH
#define AT_EMPTY_PATH 0x1000
#endif
#ifndef MFD_CLOEXEC
#define MFD_CLOEXEC 0x0001U
#endif
static int xmemfd_create(const char *name, unsigned int flags) { return (int)syscall(SYS_memfd_create, name, flags); }
static int xexecveat(int dirfd, const char *path, char *const argv[], char *const envp[], int flags) { return (int)syscall(SYS_execveat, dirfd, path, argv, envp, flags); }
int main(void) {
  int in = open("/bin/true", O_RDONLY);
  if (in < 0) { perror("open /bin/true"); return 2; }
  int memfd = xmemfd_create("tamandua_execveat_memfd_live", 0);
  if (memfd < 0) { perror("memfd_create"); return 3; }
  char buf[8192];
  for (;;) {
    ssize_t n = read(in, buf, sizeof(buf));
    if (n < 0) { perror("read"); return 4; }
    if (n == 0) break;
    if (write(memfd, buf, (size_t)n) != n) { perror("write memfd"); return 5; }
  }
  close(in);
  lseek(memfd, 0, SEEK_SET);
  char *argv[] = {"tamandua-execveat-memfd-live", NULL};
  char *envp[] = {"TAMANDUA_EXECVEAT_MEMFD_LIVE=1", NULL};
  xexecveat(memfd, "", argv, envp, AT_EMPTY_PATH);
  perror("execveat");
  return 6;
}
EOF
cc "$work/execveat_memfd.c" -O2 -Wall -Wextra -o "$work/execveat_memfd"; "$work/execveat_memfd"; printf "tamandua_execveat_memfd_live completed=true marker=tamandua_execveat_memfd_live\n"'
